import{_ as e,c as l,o as a,a7 as d}from"./chunks/framework.DPTpzYjp.js";const h=JSON.parse('{"title":"机巢 API","description":"","frontmatter":{},"headers":[],"relativePath":"orbitcontrol/tech-spec/peripherals/dock.md","filePath":"orbitcontrol/tech-spec/peripherals/dock.md"}'),r={name:"orbitcontrol/tech-spec/peripherals/dock.md"};function i(n,t,s,o,g,x){return a(),l("div",null,t[0]||(t[0]=[d('<h1 id="机巢-api" tabindex="-1">机巢 API <a class="header-anchor" href="#机巢-api" aria-label="Permalink to &quot;机巢 API&quot;">​</a></h1><h2 id="通信协议" tabindex="-1">通信协议 <a class="header-anchor" href="#通信协议" aria-label="Permalink to &quot;通信协议&quot;">​</a></h2><ul><li><strong>通信接口</strong>: RS-485</li><li><strong>协议类型</strong>: Modbus RTU</li><li><strong>校验方式</strong>: CRC16</li><li><strong>波特率</strong>: 9600</li><li><strong>电机控制器地址</strong>: 0x07</li></ul><h2 id="开舱控制" tabindex="-1">开舱控制 <a class="header-anchor" href="#开舱控制" aria-label="Permalink to &quot;开舱控制&quot;">​</a></h2><p>控制机巢舱门打开。</p><ul><li><strong>功能码</strong>: 0x06（写单个寄存器）</li><li><strong>寄存器地址</strong>: 0x0000</li><li><strong>命令</strong>: 0x0001（开）</li><li><strong>完整报文</strong>: <code>07 06 00 00 00 01 48 6C</code></li></ul><table tabindex="0"><thead><tr><th style="text-align:left;">字节</th><th style="text-align:left;">值</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;">0x07</td><td style="text-align:left;">从站地址</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;">0x06</td><td style="text-align:left;">功能码</td></tr><tr><td style="text-align:left;">3-4</td><td style="text-align:left;">0x0000</td><td style="text-align:left;">寄存器地址</td></tr><tr><td style="text-align:left;">5-6</td><td style="text-align:left;">0x0001</td><td style="text-align:left;">写入值（开）</td></tr><tr><td style="text-align:left;">7-8</td><td style="text-align:left;">0x486C</td><td style="text-align:left;">CRC16 校验</td></tr></tbody></table><h2 id="关舱控制" tabindex="-1">关舱控制 <a class="header-anchor" href="#关舱控制" aria-label="Permalink to &quot;关舱控制&quot;">​</a></h2><p>控制机巢舱门关闭。</p><ul><li><strong>功能码</strong>: 0x06（写单个寄存器）</li><li><strong>寄存器地址</strong>: 0x0000</li><li><strong>命令</strong>: 0x0000（关）</li><li><strong>完整报文</strong>: <code>07 06 00 00 00 00 89 AC</code></li></ul><table tabindex="0"><thead><tr><th style="text-align:left;">字节</th><th style="text-align:left;">值</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;">0x07</td><td style="text-align:left;">从站地址</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;">0x06</td><td style="text-align:left;">功能码</td></tr><tr><td style="text-align:left;">3-4</td><td style="text-align:left;">0x0000</td><td style="text-align:left;">寄存器地址</td></tr><tr><td style="text-align:left;">5-6</td><td style="text-align:left;">0x0000</td><td style="text-align:left;">写入值（关）</td></tr><tr><td style="text-align:left;">7-8</td><td style="text-align:left;">0x89AC</td><td style="text-align:left;">CRC16 校验</td></tr></tbody></table><h2 id="响应格式" tabindex="-1">响应格式 <a class="header-anchor" href="#响应格式" aria-label="Permalink to &quot;响应格式&quot;">​</a></h2><p>控制器正常响应时返回：</p><ul><li><strong>开舱响应</strong>: <code>07 06 00 00 00 01 48 6C</code></li><li><strong>关舱响应</strong>: <code>07 06 00 00 00 00 89 AC</code></li></ul><p>响应报文与命令报文相同（Modbus 标准响应）。</p>',15)]))}const c=e(r,[["render",i]]);export{h as __pageData,c as default};
